<template>
	<div
		v-if="show"
		class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"
		@click.self="handleCancel"
	>
		<div class="bg-white rounded-lg shadow-xl max-w-lg w-full mx-4">
			<!-- Header -->
			<div class="px-6 py-4 border-b">
				<h3 class="text-lg font-semibold">
					{{ existingAssignment ? "Edytuj przypisanie" : "Dodaj przypisanie projektu" }}
				</h3>
				<p class="text-sm text-gray-500">{{ employeeName }}</p>
			</div>

			<!-- Body -->
			<div class="px-6 py-4 space-y-4">
				<!-- Project selector -->
				<div>
					<label class="block text-sm font-medium mb-1">Projekt *</label>
					<select
						v-model="form.project"
						class="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
					>
						<option value="">-- Wybierz projekt --</option>
						<option
							v-for="proj in availableProjects"
							:key="proj.name"
							:value="proj.name"
						>
							{{ proj.project_name }}
						</option>
					</select>
					<p v-if="availableProjects.length === 0" class="text-xs text-gray-500 mt-1">
						Brak aktywnych projektów dla tego pracownika
					</p>
				</div>

				<!-- Date range -->
				<div class="grid grid-cols-2 gap-3">
					<div>
						<label class="block text-sm font-medium mb-1">Od *</label>
						<input
							v-model="form.from_date"
							type="date"
							:min="weekStart"
							:max="weekEnd"
							class="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
						/>
					</div>
					<div>
						<label class="block text-sm font-medium mb-1">Do *</label>
						<input
							v-model="form.to_date"
							type="date"
							:min="form.from_date || weekStart"
							:max="weekEnd"
							class="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
						/>
					</div>
				</div>

				<!-- Hours per day -->
				<div>
					<label class="block text-sm font-medium mb-1">Godzin/dzień *</label>
					<input
						v-model.number="form.hours_per_day"
						type="number"
						step="0.5"
						min="0.5"
						max="24"
						class="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
					/>
				</div>

				<!-- Overbooking warning (frontend, non-blocking) -->
				<div v-if="isOverbooked" class="bg-orange-50 border-l-4 border-orange-500 p-3">
					<p class="text-sm text-orange-700 font-medium">
						⚠ Łączne godziny w tym dniu przekroczą 8h.
					</p>
					<p class="text-xs text-orange-600 mt-1">
						Przypisanie zostanie mimo to zapisane.
					</p>
				</div>

				<!-- Summary line -->
				<div class="text-sm text-gray-600">
					Istniejące przypisanie tego dnia:
					<span class="font-semibold">{{ currentDayTotal.toFixed(1) }}h</span>
					→ po dodaniu:
					<span :class="previewClass" class="font-semibold">
						{{ (currentDayTotal + hoursValue).toFixed(1) }}h
					</span>
				</div>
			</div>

			<!-- Footer -->
			<div class="px-6 py-4 border-t flex justify-between gap-2">
				<button
					v-if="existingAssignment"
					@click="handleDelete"
					class="px-4 py-2 border border-red-300 text-red-600 rounded hover:bg-red-50 transition-colors"
				>
					Usuń
				</button>
				<div class="flex gap-2 ml-auto">
					<button
						@click="handleCancel"
						class="px-4 py-2 border rounded hover:bg-gray-50 transition-colors"
					>
						Anuluj
					</button>
					<button
						@click="handleConfirm"
						class="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 transition-colors"
					>
						{{ existingAssignment ? "Zapisz" : "Dodaj" }}
					</button>
				</div>
			</div>
		</div>
	</div>
</template>

<script setup>
import { ref, reactive, computed, watch } from "vue";

const props = defineProps({
	show: { type: Boolean, required: true },
	employee: { type: String, default: null },
	employeeName: { type: String, default: "" },
	date: { type: String, default: null }, // clicked cell date
	weekStart: { type: String, default: null }, // Monday YYYY-MM-DD
	weekEnd: { type: String, default: null }, // Friday YYYY-MM-DD
	currentDayTotal: { type: Number, default: 0 }, // sum of existing hours that day
	existingAssignment: { type: Object, default: null }, // for edit mode
	availableProjects: { type: Array, default: () => [] }, // list of active projects
});

const emit = defineEmits(["update:show", "confirm", "delete"]);

const form = reactive({
	project: "",
	from_date: props.weekStart,
	to_date: props.weekEnd,
	hours_per_day: 8,
});

// Reset form when modal opens
watch(
	() => props.show,
	(val) => {
		if (val) {
			if (props.existingAssignment) {
				// Edit mode: pre-fill
				form.project = props.existingAssignment.project;
				form.from_date = props.existingAssignment.from_date;
				form.to_date = props.existingAssignment.to_date;
				form.hours_per_day = props.existingAssignment.hours_per_day;
			} else {
				// Create mode: default to clicked date, 8h/day
				form.project = "";
				form.from_date = props.date || props.weekStart;
				form.to_date = props.date || props.weekEnd;
				form.hours_per_day = 8;
			}
		}
	}
);

const hoursValue = computed(() => Number(form.hours_per_day) || 0);

const isOverbooked = computed(() => props.currentDayTotal + hoursValue.value > 8.01);

const previewClass = computed(() => {
	const total = props.currentDayTotal + hoursValue.value;
	if (total > 8.01) return "text-red-600";
	if (total >= 7.99) return "text-green-600";
	return "text-yellow-600";
});

function handleConfirm() {
	// Simple validation
	if (!form.project || !form.from_date || !form.to_date || !form.hours_per_day) {
		if (window.frappe) {
			frappe.show_alert({
				message: "Proszę wypełnić wszystkie wymagane pola",
				indicator: "orange",
			});
		}
		return;
	}

	emit("confirm", {
		employee: props.employee,
		project: form.project,
		from_date: form.from_date,
		to_date: form.to_date,
		hours_per_day: form.hours_per_day,
		assignmentId: props.existingAssignment?.name ?? null,
	});

	emit("update:show", false);
}

function handleDelete() {
	emit("delete", props.existingAssignment.name);
	emit("update:show", false);
}

function handleCancel() {
	emit("update:show", false);
}
</script>
