<template>
	<div
		class="capacity-day-cell p-1.5 sm:p-2 border-r min-h-20 sm:min-h-24 transition-colors"
		:class="[cellBgClass, readonly ? 'cursor-default' : 'cursor-pointer']"
		@click="!readonly && emit('click')"
	>
		<!-- Capacity Progress Bar -->
		<div class="capacity-bar h-1 mb-2 rounded-full bg-gray-200">
			<div
				class="h-full rounded-full transition-all"
				:class="progressColorClass"
				:style="{ width: capacityPercent + '%' }"
			/>
		</div>

		<!-- Project chips -->
		<div class="space-y-1">
			<ProjectChip
				v-for="entry in cellData.entries"
				:key="entry.assignment_name"
				:entry="entry"
				:readonly="readonly"
				@edit="emit('edit-assignment', $event)"
				@delete="emit('delete-assignment', $event)"
			/>
		</div>

		<!-- Daily sum badge -->
		<div
			v-if="cellData.daily_total > 0"
			class="text-xs text-center mt-1 font-semibold px-1 py-0.5 rounded"
			:class="sumBadgeClass"
		>
			{{ cellData.daily_total.toFixed(1) }}h
		</div>

		<!-- Actual hours badge -->
		<div
			v-if="showActualBadge"
			class="text-xs mt-1 flex items-center justify-end gap-0.5 px-1 py-0.5 rounded font-semibold"
			:class="actualBadgeClass"
		>
			<span>{{ actualBadgeIcon }} {{ actualHours.toFixed(1) }}h</span>
		</div>

		<!-- Overbooked warning icon -->
		<div v-if="cellData.is_overbooked" class="text-xs text-red-600 text-center mt-0.5">⚠</div>

		<!-- Empty state (click to add) — hidden for read-only users -->
		<div
			v-if="cellData.entries.length === 0 && !readonly"
			class="text-xs text-gray-300 text-center mt-2"
		>
			+ Dodaj
		</div>
	</div>
</template>

<script setup>
import { computed } from "vue";
import ProjectChip from "./ProjectChip.vue";

const props = defineProps({
	cellData: {
		type: Object,
		default: () => ({ entries: [], daily_total: 0, is_overbooked: false }),
	},
	actualHours: { type: Number, default: 0 },
	employee: { type: String, required: true },
	date: { type: String, required: true },
	readonly: { type: Boolean, default: false },
});

const emit = defineEmits(["click", "edit-assignment", "delete-assignment"]);

// CRITICAL color coding logic
// daily_total = 0      → no background (grey/empty)
// 0 < daily_total < 8  → yellow background (underloaded)
// daily_total ≈ 8      → green background (perfect)
// daily_total > 8      → red background (overbooked)

const TOLERANCE = 0.01;

const cellBgClass = computed(() => {
	const h = props.cellData.daily_total;
	if (h <= 0) return ""; // empty - no highlight
	if (h > 8 + TOLERANCE) return "bg-red-50"; // overbooked
	if (h >= 8 - TOLERANCE) return "bg-green-50"; // perfect (7.99 - 8.01)
	return "bg-yellow-50"; // underloaded (h > 0 && h < 8)
});

const sumBadgeClass = computed(() => {
	const h = props.cellData.daily_total;
	if (h > 8 + TOLERANCE) return "bg-red-100 text-red-700";
	if (h >= 8 - TOLERANCE) return "bg-green-100 text-green-700";
	return "bg-yellow-100 text-yellow-700";
});

// Progress bar calculations
const capacityPercent = computed(() => {
	const percent = (props.cellData.daily_total / 8) * 100;
	return Math.min(percent, 100);
});

const progressColorClass = computed(() => {
	const h = props.cellData.daily_total;
	if (h > 10) return "bg-red-500";
	if (h > 8 + TOLERANCE) return "bg-orange-500";
	if (h >= 8 - TOLERANCE) return "bg-green-500";
	return "bg-blue-500";
});

const showActualBadge = computed(() => props.cellData.daily_total > 0 || props.actualHours > 0);

const actualBadgeClass = computed(() => {
	const planned = props.cellData.daily_total;
	const actual = props.actualHours;
	if (actual <= 0) return "bg-red-100 text-red-700";
	if (planned <= 0) return "bg-green-100 text-green-700";
	const ratio = actual / planned;
	if (ratio >= 0.9 && ratio <= 1.1) return "bg-green-100 text-green-700";
	if (ratio > 1.1) return "bg-blue-100 text-blue-700";
	return "bg-orange-100 text-orange-700";
});

const actualBadgeIcon = computed(() => {
	const planned = props.cellData.daily_total;
	const actual = props.actualHours;
	if (actual <= 0) return "✗";
	if (planned <= 0) return "✓";
	const ratio = actual / planned;
	if (ratio >= 0.9 && ratio <= 1.1) return "✓";
	if (ratio > 1.1) return "↑";
	return "↓";
});
</script>
